let d = msg.payload;

let power = 0;
let energy_kwh = 0;
let voltage = 0;
let current = 0;

// -----------------------------
// Shelly Gen‑1 (1PM, EM, 2.5)
// -----------------------------
if (d.meters && d.meters[0]) {
    let m = d.meters[0];

    if (typeof m.power === "number") {
        power = m.power;
    }
    if (m.counters && typeof m.counters[0] === "number") {
        energy_kwh = m.counters[0] / 1000;   // Wh → kWh
    }

    // Gen‑1 1PM does NOT measure voltage/current
    if (typeof m.voltage === "number") {
        voltage = m.voltage;
    }
    if (typeof m.current === "number") {
        current = m.current;
    }
}

// -----------------------------
// Shelly Plus / Pro (RPC API)
// -----------------------------
if (typeof d.apower === "number") {
    power = Math.abs(d.apower);
}
if (d.ret_aenergy && typeof d.ret_aenergy.total === "number") {
    energy_kwh = d.ret_aenergy.total / 1000;
}
if (typeof d.voltage === "number") {
    voltage = d.voltage;
}
if (typeof d.current === "number") {
    current = d.current;
}

// -----------------------------
// Output to Virtual PV Inverter
// -----------------------------
msg.payload = {
    "Ac/Power": power,
    "Ac/Energy/Forward": energy_kwh,
    "Ac/L1/Power": power,
    "Ac/L1/Energy/Forward": energy_kwh,
    "Ac/L1/Voltage": voltage,
    "Ac/L1/Current": current,
    "StatusCode": 7
};
// -------------------------------------
// Set a unique devide instance ID here
// -------------------------------------
msg.payload["/DeviceInstance"] = 102;

return msg;

info:
for Gen1 Shelly pm switches use the following URL and insert the IP of your device:
http://<ip-address>/status

for Shelly devices Gen2 and newer use this URL and replace the IP accordingly:
http://<ip-address>/rpc/Switch.GetStatus?id=0
